%[text] ## Gerard Gajda C6
%[text] #### 6.1 Zmienne globalne
global A B C;

A = 1; %[control:editfield:83e6]{"position":[5,6]}
B = 1; %[control:editfield:8d13]{"position":[5,6]}
C = 0; %[control:editfield:30ff]{"position":[5,6]}

[x1,x2] = f_trojm2(); %[output:51e7016a]

disp([x1;x2]); %[output:00f888fa]

r = roots([A B C]);
disp(r); %[output:847bdf32]

clear global A B C;
%[text] #### 6.2 Funkcja dwu zmiennych
% x = -1:0.1:1;
% y = x;
% [X,Y] = meshgrid(x);
% 
% F = X.*exp(-X.^2-Y.^2);
% mesh(X,Y,F)

res = 1000; %[control:slider:2833]{"position":[7,11]}

x = linspace(-1, 1, res);
y = linspace(-1, 1, res);
[X, Y] = meshgrid(x, y);

bound = 15; %[control:slider:8ac7]{"position":[9,11]}

F = waerden(x,y,bound);

% Surf
figure; %[output:5117b9b1]
if (res < 100)
    surf(X, Y, F);
else
    surf(X, Y, F, 'EdgeColor', 'none'); %[output:5117b9b1]
end
colormap parula; %[output:5117b9b1]
colorbar; %[output:5117b9b1]
title('Surf: f(x,y) = (1+V(x))(1+V(y))'); %[output:5117b9b1]
xlabel('x'); %[output:5117b9b1]
ylabel('y'); %[output:5117b9b1]
zlabel('f(x,y)'); %[output:5117b9b1]
view([-45 45]); %[output:5117b9b1]

% Mesh
figure; %[output:0749f798]
mesh(X, Y, F); %[output:0749f798]
colormap parula; %[output:0749f798]
colorbar; %[output:0749f798]
title('Mesh: f(x,y) = (1+V(x))(1+V(y))'); %[output:0749f798]
xlabel('x'); %[output:0749f798]
ylabel('y'); %[output:0749f798]
zlabel('f(x,y)'); %[output:0749f798]
view([-45 45]); %[output:0749f798]

% Contour
figure; %[output:90567e5e]
contour(X, Y, F); %[output:90567e5e]
colormap parula; %[output:90567e5e]
colorbar; %[output:90567e5e]
title('Contour: f(x,y) = (1+V(x))(1+V(y))'); %[output:90567e5e]
xlabel('x'); %[output:90567e5e]
ylabel('y'); %[output:90567e5e]
zlabel('f(x,y)'); %[output:90567e5e]
view([-45 45]); %[output:90567e5e]

% Meshc
figure; %[output:934ea590]
meshc(X, Y, F); %[output:934ea590]
colormap parula; %[output:934ea590]
colorbar; %[output:934ea590]
title('Meshc: f(x,y) = (1+V(x))(1+V(y))'); %[output:934ea590]
xlabel('x'); %[output:934ea590]
ylabel('y'); %[output:934ea590]
zlabel('f(x,y)'); %[output:934ea590]
view([-45 45]); %[output:934ea590]

